VALUES
  ('retired-7c9828ae-moex-00087', 'retired-7c9828ae', 'retired-7c9828ae-moex-114-3082b5f1', 'sub-retired-7c9828ae-06', NULL, 'single_choice', '關於行政處分之敘述，下列何者錯誤？', '["行政處分違背法規有關專屬管轄之規定，該處分並非無效，故相對人僅得請求撤銷", "行政機關經聽證後作成之行政處分，如人民不服該處分，得直接向行政法院提起訴訟", "行政機關作成書面之行政處分，應送達處分之相對人及已知之利害關係人", "行政處分有誤寫誤繕之顯然錯誤時，原處分機關得依職權隨時更正"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:27:08+00:00", "source_pdf_sha1": "08231c21eb42", "answer_pdf_sha1": "647b6f5bbf6b", "source_family": "moex-gov-tw", "moex": {"exam_code": "114060", "c": "134", "s": "0403", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "行政法", "year": "114", "exam_name": "114年公務人員特種考試警察人員考試、一般警察人員考試、國家安全情報人員考試、移民行政人員考試、退除役軍人轉任公務人員考試", "original_question_number": 12, "answer_corrected": false, "flags": [], "civil_slug": "retired", "civil_category": "社會工作"}'::jsonb, NULL),
  ('retired-7c9828ae-moex-00088', 'retired-7c9828ae', 'retired-7c9828ae-moex-114-3082b5f1', 'sub-retired-7c9828ae-06', NULL, 'single_choice', '行政機關以行政處分核准甲一筆補助款，嗣後發現甲根本不符合申請資格。關於行政機關取回補 助款之敘述，下列何者正確？', '["因甲違法取得補助款，行政機關撤銷行政處分無須考量其信賴是否值得保護", "行政機關得與甲簽訂和解契約，約定分期給付之條件", "行政機關得以行政處分命甲返還受領之補助款", "甲若拒絕返還補助款，行政機關應向行政法院提起一般給付之訴"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:27:08+00:00", "source_pdf_sha1": "08231c21eb42", "answer_pdf_sha1": "647b6f5bbf6b", "source_family": "moex-gov-tw", "moex": {"exam_code": "114060", "c": "134", "s": "0403", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "行政法", "year": "114", "exam_name": "114年公務人員特種考試警察人員考試、一般警察人員考試、國家安全情報人員考試、移民行政人員考試、退除役軍人轉任公務人員考試", "original_question_number": 13, "answer_corrected": false, "flags": [], "civil_slug": "retired", "civil_category": "社會工作"}'::jsonb, NULL),
  ('retired-7c9828ae-moex-00089', 'retired-7c9828ae', 'retired-7c9828ae-moex-114-3082b5f1', 'sub-retired-7c9828ae-06', NULL, 'single_choice', '現行菸害防制法規定各級學校內全面禁菸，某公立大學乃公告「配合菸害防制法之修正施行，本 校即日起撤除吸菸室／區」，該公告之法律性質為何？', '["該公告未直接限制師生吸菸之權利，並非行政處分", "該公告重申法律規定內涵，屬於觀念通知", "該公告涉及公物之一般使用方式，構成一般處分", "該公告規範對象為校內外所有人，屬於大學之自治規章"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:27:08+00:00", "source_pdf_sha1": "08231c21eb42", "answer_pdf_sha1": "647b6f5bbf6b", "source_family": "moex-gov-tw", "moex": {"exam_code": "114060", "c": "134", "s": "0403", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "行政法", "year": "114", "exam_name": "114年公務人員特種考試警察人員考試、一般警察人員考試、國家安全情報人員考試、移民行政人員考試、退除役軍人轉任公務人員考試", "original_question_number": 14, "answer_corrected": false, "flags": [], "civil_slug": "retired", "civil_category": "社會工作"}'::jsonb, NULL),
  ('retired-7c9828ae-moex-00090', 'retired-7c9828ae', 'retired-7c9828ae-moex-114-3082b5f1', 'sub-retired-7c9828ae-06', NULL, 'single_choice', '有關行政程序法上和解契約之敘述，下列何者錯誤？', '["課稅事件亦得締結和解契約", "和解契約應以行政處分所依據之事實或法律關係不明確，雖經依職權調查，仍不能確定為前提要件", "和解契約係為替代行政處分", "基於行政之公益目的原則，行政機關所簽訂之和解契約不得讓步"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:27:08+00:00", "source_pdf_sha1": "08231c21eb42", "answer_pdf_sha1": "647b6f5bbf6b", "source_family": "moex-gov-tw", "moex": {"exam_code": "114060", "c": "134", "s": "0403", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "行政法", "year": "114", "exam_name": "114年公務人員特種考試警察人員考試、一般警察人員考試、國家安全情報人員考試、移民行政人員考試、退除役軍人轉任公務人員考試", "original_question_number": 15, "answer_corrected": false, "flags": [], "civil_slug": "retired", "civil_category": "社會工作"}'::jsonb, NULL),
  ('retired-7c9828ae-moex-00091', 'retired-7c9828ae', 'retired-7c9828ae-moex-114-3082b5f1', 'sub-retired-7c9828ae-06', NULL, 'single_choice', '關於行政事實行為之敘述，下列何者正確？', '["行政事實行為不足以構成信賴基礎", "兩個地號間界址之鑑定，非行政事實行為", "行政機關對採購異議之處理決定，非行政事實行為", "行政事實行為不適用法律保留原則 13720、30120"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:27:08+00:00", "source_pdf_sha1": "08231c21eb42", "answer_pdf_sha1": "647b6f5bbf6b", "source_family": "moex-gov-tw", "moex": {"exam_code": "114060", "c": "134", "s": "0403", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "行政法", "year": "114", "exam_name": "114年公務人員特種考試警察人員考試、一般警察人員考試、國家安全情報人員考試、移民行政人員考試、退除役軍人轉任公務人員考試", "original_question_number": 16, "answer_corrected": false, "flags": [], "civil_slug": "retired", "civil_category": "社會工作"}'::jsonb, NULL),
  ('retired-7c9828ae-moex-00092', 'retired-7c9828ae', 'retired-7c9828ae-moex-114-3082b5f1', 'sub-retired-7c9828ae-06', NULL, 'single_choice', '依行政法院實務見解，下列何者為裁罰性不利處分？', '["機關對於得標後未於規定期限內繳足保證金之廠商追繳已發還之押標金", "機關對於正進行破產程序中之廠商為將刊登政府採購公報之通知", "機關對未經核准而違法經營公路經營業之業者，吊扣其車輛牌照", "會計師懲戒委員會對違反業務事件主管機關法令之會計師所施予之懲戒"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:27:08+00:00", "source_pdf_sha1": "08231c21eb42", "answer_pdf_sha1": "647b6f5bbf6b", "source_family": "moex-gov-tw", "moex": {"exam_code": "114060", "c": "134", "s": "0403", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "行政法", "year": "114", "exam_name": "114年公務人員特種考試警察人員考試、一般警察人員考試、國家安全情報人員考試、移民行政人員考試、退除役軍人轉任公務人員考試", "original_question_number": 17, "answer_corrected": false, "flags": [], "civil_slug": "retired", "civil_category": "社會工作"}'::jsonb, NULL),
  ('retired-7c9828ae-moex-00093', 'retired-7c9828ae', 'retired-7c9828ae-moex-114-3082b5f1', 'sub-retired-7c9828ae-06', NULL, 'single_choice', '甲於自家房屋周圍無圍牆之土地上放置大量廚餘，發出惡臭，廢棄物清理法執行機關 A 市環保 局開立限期清理通知書，命甲10日內清除處理廢棄物。甲屆期仍不為清除，為維持環境衛生， 機關應如何處理？', '["A市環保局只得持續開立限期清理通知書", "A市環保局得請求自來水公司與電力公司對於甲屋為斷水、斷電處置", "A市環保局得直接作成科處新臺幣5,000元以上之怠金", "A市環保局得委託民營廢棄物清理機構代為清除，清除費用由甲負擔"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:27:08+00:00", "source_pdf_sha1": "08231c21eb42", "answer_pdf_sha1": "647b6f5bbf6b", "source_family": "moex-gov-tw", "moex": {"exam_code": "114060", "c": "134", "s": "0403", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "行政法", "year": "114", "exam_name": "114年公務人員特種考試警察人員考試、一般警察人員考試、國家安全情報人員考試、移民行政人員考試、退除役軍人轉任公務人員考試", "original_question_number": 18, "answer_corrected": false, "flags": [], "civil_slug": "retired", "civil_category": "社會工作"}'::jsonb, NULL),
